mapper.select:
select pf.*, cp.child_name, p.real_name as parent_name, t.real_name as teacher_name from parent_feedback pf left join child_profile cp on pf.child_id = cp.id left join sys_user p on pf.parent_id = p.id left join sys_user t on pf.teacher_id = t.id
and pf.child_id = #{childId}
and pf.parent_id = #{parentId}
and pf.teacher_id = #{teacherId}
order by pf.id desc

mapper.update:
update parent_feedback
teacher_id = #{teacherId}, reply_content = #{replyContent}, feedback_type = #{feedbackType}, feedback_score = #{feedbackScore}, feedback_content = #{feedbackContent},
where id = #{id}
